import React, { useState } from 'react';
import './App.css'; // Your styles

const GeneratorForm = () => {
  const [description, setDescription] = useState('');

  const handleStyleSelect = (style) => {
    setDescription(style); // Update description with the selected style
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle form submission logic
    console.log(`Generating NFT with description: "${description}"`);
  };

  return (
    <div className="generator-container">
      <h2 className="form-title">Choose Your Style</h2>
      <p className="form-description">
        Select the style of art you'd like to generate from the options below:
      </p>

      {/* Custom Select Dropdown */}
      <div className="custom-select" id="style-select">
        <div onClick={() => handleStyleSelect("Digital Art")}>Digital Art</div>
        <div onClick={() => handleStyleSelect("Abstract")}>Abstract</div>
        <div onClick={() => handleStyleSelect("Oil Painting")}>Oil Painting</div>
        <div onClick={() => handleStyleSelect("Watercolor")}>Watercolor</div>
      </div>

      {/* Form for Input */}
      <form className="generator-form" onSubmit={handleSubmit}>
        <input
          className="form-input"
          type="text"
          placeholder="Describe your image..."
          value={description}
          onChange={(e) => setDescription(e.target.value)}
        />
        <button className="submit-button" type="submit">
          Generate
        </button>
      </form>
    </div>
  );
};

export default GeneratorForm;
